import json
import logging
import os
from datetime import datetime, timezone
from typing import Any, Dict, Optional

import azure.functions as func
from azure.identity import ManagedIdentityCredential
from azure.storage.blob import BlobClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.core.credentials import AzureKeyCredential
from azure.eventgrid import EventGridPublisherClient, EventGridEvent

app = func.FunctionApp()

STORAGE_ACCOUNT_URL = os.environ["STORAGE_ACCOUNT_URL"]
COSMOS_ACCOUNT_URI = os.environ["COSMOS_ACCOUNT_URI"]
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "mvp-db")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "processed-files")
EVENT_GRID_TOPIC_ENDPOINT = os.environ["EVENT_GRID_TOPIC_ENDPOINT"]

IDENTITY_CLIENT_ID = os.environ.get("MANAGED_IDENTITY_CLIENT_ID")

credential = ManagedIdentityCredential(client_id=IDENTITY_CLIENT_ID) if IDENTITY_CLIENT_ID else ManagedIdentityCredential()

COSMOS_KEY = os.environ.get("COSMOS_KEY")
EVENT_GRID_KEY = os.environ.get("EVENT_GRID_KEY")

def get_blob_client(blob_url: str) -> BlobClient:
    return BlobClient.from_blob_url(blob_url, credential=credential)

def get_cosmos_client() -> CosmosClient:
    if COSMOS_KEY:
        return CosmosClient(COSMOS_ACCOUNT_URI, credential=COSMOS_KEY)
    return CosmosClient(COSMOS_ACCOUNT_URI, credential=credential)

def get_event_grid_client() -> EventGridPublisherClient:
    if EVENT_GRID_KEY:
        return EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, AzureKeyCredential(EVENT_GRID_KEY))
    return EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, credential)

def ensure_container(cosmos_client: CosmosClient):
    db = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = db.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path="/blobName"),
    )
    return container

def parse_blob_url(blob_url: str) -> Dict[str, str]:
    path = blob_url.split(".net/", 1)[1]
    parts = path.split("/", 1)
    container = parts[0]
    blob_name = parts[1] if len(parts) > 1 else ""
    return {"container": container, "blobName": blob_name}

def process_content(content: bytes, metadata: Dict[str, Any]) -> Dict[str, Any]:
    text = content.decode("utf-8", errors="replace")
    lines = text.splitlines()
    words = text.split()
    return {
        "sizeBytes": len(content),
        "lineCount": len(lines),
        "wordCount": len(words),
        "preview": text[:500],
        "processedAt": datetime.now(timezone.utc).isoformat(),
        "metadata": metadata,
    }

def build_document(blob_url: str, analysis: Dict[str, Any]) -> Dict[str, Any]:
    blob_info = parse_blob_url(blob_url)
    return {
        "id": f"{blob_info['container']}:{blob_info['blobName']}:{int(datetime.now(timezone.utc).timestamp())}",
        "blobUrl": blob_url,
        "container": blob_info["container"],
        "blobName": blob_info["blobName"],
        **analysis,
    }

def send_notification(client: EventGridPublisherClient, doc: Dict[str, Any]) -> None:
    event = EventGridEvent(
        subject=f"/blobs/{doc['container']}/{doc['blobName']}",
        event_type="Contoso.Files.Processed",
        data_version="1.0",
        data={
            "id": doc["id"],
            "blobUrl": doc["blobUrl"],
            "container": doc["container"],
            "blobName": doc["blobName"],
            "processedAt": doc["processedAt"],
            "sizeBytes": doc["sizeBytes"],
            "lineCount": doc["lineCount"],
            "wordCount": doc["wordCount"],
        },
    )
    client.send([event])

@app.function_name(name="ProcessBlobToCosmosAndNotify")
@app.blob_trigger(arg_name="inputblob", path="incoming/{name}", connection="AzureWebJobsStorage")
def main(inputblob: func.InputStream) -> None:
    blob_name = inputblob.name
    blob_len = inputblob.length or 0
    blob_uri = f"{STORAGE_ACCOUNT_URL.rstrip('/')}/{blob_name}"

    logging.info("Processing blob: %s (%s bytes)", blob_name, blob_len)

    blob_client = get_blob_client(blob_uri)
    downloaded = blob_client.download_blob()
    content = downloaded.readall()
    props = blob_client.get_blob_properties()

    metadata = {
        "etag": props.etag,
        "contentType": props.content_settings.content_type if props.content_settings else None,
        "lastModified": props.last_modified.isoformat() if props.last_modified else None,
        "size": props.size,
    }

    analysis = process_content(content, metadata)
    document = build_document(blob_uri, analysis)

    cosmos_client = get_cosmos_client()
    container = ensure_container(cosmos_client)
    container.upsert_item(document)

    event_grid_client = get_event_grid_client()
    send_notification(event_grid_client, document)

    logging.info("Completed processing for blob: %s", blob_name)